349→<script>
350→// ============================================================================
351→// State
352→// ============================================================================
353→let ws = null;
354→let audioCtx = null;       // capture context (16kHz)
355→let playbackCtx = null;    // playback context (24kHz)
356→let mediaStream = null;
357→let analyser = null;
358→let processor = null;
359→let videoStream = null;
360→let videoInterval = null;
361→let animFrame = null;
362→let nextPlayTime = 0;
363→let sessionActive = false;
364→
365→// Onset detection
366→const onsets = [];          // { time: seconds since session start }
367→let sessionStartTime = 0;
368→let prevRms = 0;
369→const ONSET_THRESHOLD = 0.06;
370→const ONSET_COOLDOWN = 0.08;  // min seconds between onsets
371→let lastOnsetTime = 0;
372→
373→// BPM
374→const bpmSlider = document.getElementById('bpmSlider');
375→const bpmVal = document.getElementById('bpmVal');
376→bpmSlider.addEventListener('input', () => { bpmVal.textContent = bpmSlider.value; });
377→
378→// ============================================================================
379→// Session management
380→// ============================================================================
381→async function startSession() {
382→  document.getElementById('btnStart').disabled = true;
383→  document.getElementById('btnStop').disabled = false;
384→  setStatus('connecting');
385→
386→  try {
387→    // Request camera + mic
388→    mediaStream = await navigator.mediaDevices.getUserMedia({
389→      audio: { echoCancellation: false, noiseSuppression: false, autoGainControl: false },
390→      video: { width: 640, height: 480, facingMode: 'user' }
391→    });
392→
393→    // Show camera
394→    const video = document.getElementById('cameraVideo');
395→    video.srcObject = mediaStream;
396→    document.getElementById('videoPlaceholder').style.display = 'none';
397→
398→    // Audio capture context at 16kHz
399→    audioCtx = new AudioContext({ sampleRate: 16000 });
400→    const source = audioCtx.createMediaStreamSource(mediaStream);
401→
402→    // Analyser for visualization (use higher FFT for piano frequency resolution)
403→    analyser = audioCtx.createAnalyser();
404→    analyser.fftSize = 2048;
405→    analyser.smoothingTimeConstant = 0.8;
406→    source.connect(analyser);
407→
408→    // ScriptProcessor for PCM capture → WebSocket
409→    processor = audioCtx.createScriptProcessor(4096, 1, 1);
410→    source.connect(processor);
411→    processor.connect(audioCtx.destination);  // must connect for processing to work
412→
413→    // Playback context at 24kHz for agent voice
414→    playbackCtx = new AudioContext({ sampleRate: 24000 });
415→    nextPlayTime = 0;
416→
417→    // WebSocket
418→    const proto = location.protocol === 'https:' ? 'wss' : 'ws';
419→    ws = new WebSocket(`${proto}://${location.host}/ws/dialog`);
420→    ws.binaryType = 'arraybuffer';
421→
422→    ws.onopen = () => {
423→      setStatus('connected');
424→      sessionActive = true;
425→      sessionStartTime = performance.now() / 1000;
426→      onsets.length = 0;
427→      addTranscript('system', 'Connected. Speak or play piano to begin.');
428→      ws.send(JSON.stringify({ type: 'set_mode', mode: 'storyteller' }));
429→
430→      // Start sending audio
431→      processor.onaudioprocess = (e) => {
432→        if (!ws || ws.readyState !== WebSocket.OPEN) return;
433→        const input = e.inputBuffer.getChannelData(0);
434→        const pcm16 = new Int16Array(input.length);
435→        for (let i = 0; i < input.length; i++) {
436→          pcm16[i] = Math.max(-32768, Math.min(32767, Math.round(input[i] * 32767)));
437→        }
438→        ws.send(pcm16.buffer);
439→      };
440→
441→      // Start sending video frames (1 frame every 2s)
442→      const captureCanvas = document.createElement('canvas');
443→      captureCanvas.width = 640;
444→      captureCanvas.height = 480;
445→      const captureCtx = captureCanvas.getContext('2d');
446→      videoInterval = setInterval(() => {
447→        if (!ws || ws.readyState !== WebSocket.OPEN) return;
448→        captureCtx.drawImage(video, 0, 0, 640, 480);
449→        const dataUrl = captureCanvas.toDataURL('image/jpeg', 0.6);
450→        const b64 = dataUrl.split(',')[1];
451→        ws.send(JSON.stringify({ type: 'video_frame', data: b64 }));
452→      }, 2000);
453→
454→      // Start visualizations
455→      drawLoop();
456→    };
457→
458→    ws.onmessage = (event) => {
459→      if (event.data instanceof ArrayBuffer) {
460→        // Audio from agent — play it
461→        queueAudio(event.data);
462→      } else {
463→        const msg = JSON.parse(event.data);
464→        if (msg.type === 'input_transcript') {
465→          addTranscript('user', msg.text);
466→        } else if (msg.type === 'output_transcript') {
467→          addTranscript('agent', msg.text);
468→        } else if (msg.type === 'turn_complete') {
469→          // optional: visual indicator
470→        } else if (msg.type === 'interrupted') {
471→          // agent was interrupted by user speech
472→        }
473→      }
474→    };
475→
476→    ws.onclose = () => {
477→      setStatus('disconnected');
478→      addTranscript('system', 'Disconnected.');
479→    };
480→
481→    ws.onerror = () => {
482→      setStatus('error');
483→    };
484→
485→  } catch (err) {
486→    console.error('Failed to start session:', err);
487→    setStatus('error');
488→    addTranscript('system', 'Error: ' + err.message);
489→    document.getElementById('btnStart').disabled = false;
490→    document.getElementById('btnStop').disabled = true;
491→  }
492→}
493→
494→function stopSession() {
495→  sessionActive = false;
496→  if (ws && ws.readyState === WebSocket.OPEN) {
497→    ws.send(JSON.stringify({ type: 'close' }));
498→    ws.close();
499→  }
500→  ws = null;
501→  if (videoInterval) { clearInterval(videoInterval); videoInterval = null; }
502→  if (animFrame) { cancelAnimationFrame(animFrame); animFrame = null; }
503→  if (processor) { processor.disconnect(); processor = null; }
504→  if (analyser) { analyser.disconnect(); analyser = null; }
505→  if (audioCtx) { audioCtx.close(); audioCtx = null; }
506→  if (playbackCtx) { playbackCtx.close(); playbackCtx = null; }
507→  if (mediaStream) {
508→    mediaStream.getTracks().forEach(t => t.stop());
509→    mediaStream = null;
510→  }
511→  document.getElementById('cameraVideo').srcObject = null;
512→  document.getElementById('videoPlaceholder').style.display = '';
513→  document.getElementById('btnStart').disabled = false;
514→  document.getElementById('btnStop').disabled = true;
515→  setStatus('disconnected');
516→}
