551→// --- MIDI Dynamic Bars ---
552→function drawMidiBars() {
553→  const canvas = document.getElementById('midiBars');
554→  const ctx = canvas.getContext('2d');
555→  const dpr = window.devicePixelRatio || 1;
556→  const rect = canvas.getBoundingClientRect();
557→  canvas.width = rect.width * dpr;
558→  canvas.height = 140 * dpr;
559→  ctx.scale(dpr, dpr);
560→  const W = rect.width;
561→  const H = 140;
562→
563→  ctx.clearRect(0, 0, W, H);
564→
565→  if (!analyser) return;
566→  const freqData = new Uint8Array(analyser.frequencyBinCount);
567→  analyser.getByteFrequencyData(freqData);
568→
569→  // Map frequency bins to piano-relevant bands (27.5Hz A0 to 4186Hz C8)
570→  // With 16kHz sample rate and FFT size 2048: bin resolution = 16000/2048 ≈ 7.8 Hz
571→  // Piano range: bin ~3 (27.5Hz) to bin ~537 (4186Hz)
572→  const binRes = 16000 / 2048;
573→  const startBin = Math.floor(27.5 / binRes);
574→  const endBin = Math.min(Math.ceil(4200 / binRes), freqData.length - 1);
575→  const numBars = 48;
576→  const binsPerBar = Math.max(1, Math.floor((endBin - startBin) / numBars));
577→  const barWidth = (W - 20) / numBars;
578→  const gap = 2;
579→
580→  for (let i = 0; i < numBars; i++) {
581→    let sum = 0;
582→    const from = startBin + i * binsPerBar;
583→    const to = Math.min(from + binsPerBar, freqData.length);
584→    for (let b = from; b < to; b++) sum += freqData[b];
585→    const avg = sum / (to - from);
586→    const normH = (avg / 255) * (H - 10);
587→
588→    // Color gradient: bass=blue/purple, mid=amber, treble=rose
589→    const t = i / numBars;
590→    let r, g, b_c;
591→    if (t < 0.33) {
592→      // purple to blue
593→      const lt = t / 0.33;
594→      r = 167 - lt * 20; g = 139 + lt * 58; b_c = 250;
595→    } else if (t < 0.66) {
596→      // blue to amber
597→      const lt = (t - 0.33) / 0.33;
598→      r = 147 + lt * 104; g = 197 - lt * 6; b_c = 253 - lt * 217;
599→    } else {
600→      // amber to rose
601→      const lt = (t - 0.66) / 0.34;
602→      r = 251; g = 191 - lt * 78; b_c = 36 + lt * 97;
603→    }
604→
605→    const x = 10 + i * barWidth;
606→    const barW = barWidth - gap;
607→
608→    // Glow effect
609→    ctx.shadowBlur = normH > 40 ? 8 : 0;
610→    ctx.shadowColor = `rgba(${r},${g},${b_c},0.4)`;
611→
612→    // Bar
613→    const gradient = ctx.createLinearGradient(0, H, 0, H - normH);
614→    gradient.addColorStop(0, `rgba(${r},${g},${b_c},0.15)`);
615→    gradient.addColorStop(1, `rgba(${r},${g},${b_c},0.8)`);
616→    ctx.fillStyle = gradient;
617→    ctx.fillRect(x, H - normH, barW, normH);
618→
619→    // Top cap
620→    ctx.shadowBlur = 0;
621→    ctx.fillStyle = `rgba(${r},${g},${b_c},0.9)`;
622→    ctx.fillRect(x, H - normH, barW, 2);
623→  }
624→}
625→
626→// --- Rhythm Accuracy Grid ---
627→function drawRhythmGrid() {
628→  const canvas = document.getElementById('rhythmGrid');
629→  const ctx = canvas.getContext('2d');
630→  const dpr = window.devicePixelRatio || 1;
631→  const rect = canvas.getBoundingClientRect();
632→  canvas.width = rect.width * dpr;
633→  canvas.height = 80 * dpr;
634→  ctx.scale(dpr, dpr);
635→  const W = rect.width;
636→  const H = 80;
637→
638→  ctx.clearRect(0, 0, W, H);
639→
640→  const bpm = parseInt(bpmSlider.value) || 90;
641→  const beatInterval = 60 / bpm;  // seconds per beat
642→  const now = performance.now() / 1000 - sessionStartTime;
643→  const windowDuration = 8;  // show 8 seconds of history
644→  const windowStart = Math.max(0, now - windowDuration);
645→
646→  // Draw beat grid lines
647→  const firstBeat = Math.ceil(windowStart / beatInterval) * beatInterval;
648→  for (let bt = firstBeat; bt < now + beatInterval; bt += beatInterval) {
649→    const x = ((bt - windowStart) / windowDuration) * W;
650→    if (x < 0 || x > W) continue;
651→
652→    // Strong beat (every 4)
653→    const beatNum = Math.round(bt / beatInterval);
654→    const isStrong = beatNum % 4 === 0;
655→
656→    ctx.strokeStyle = isStrong ? 'rgba(134,239,172,0.3)' : 'rgba(134,239,172,0.1)';
657→    ctx.lineWidth = isStrong ? 1.5 : 0.5;
658→    ctx.beginPath();
659→    ctx.moveTo(x, 5);
660→    ctx.lineTo(x, H - 5);
661→    ctx.stroke();
662→
663→    // Beat number label
664→    if (isStrong) {
665→      ctx.fillStyle = 'rgba(134,239,172,0.3)';
666→      ctx.font = '9px sans-serif';
667→      ctx.fillText(beatNum / 4 + 1, x + 2, H - 2);
668→    }
669→  }
670→
671→  // Draw onset dots
672→  for (const onset of onsets) {
673→    if (onset.time < windowStart) continue;
674→    const x = ((onset.time - windowStart) / windowDuration) * W;
675→    if (x < 0 || x > W) continue;
676→
677→    // How close to nearest beat?
678→    const nearestBeat = Math.round(onset.time / beatInterval) * beatInterval;
679→    const offset = Math.abs(onset.time - nearestBeat);
680→    const tolerance = beatInterval * 0.15;  // within 15% of beat interval
681→
682→    let color;
683→    if (offset < tolerance) {
684→      color = 'rgba(134,239,172,0.9)';  // green — on beat
685→    } else if (offset < tolerance * 2.5) {
686→      color = 'rgba(251,191,36,0.8)';   // amber — close
687→    } else {
688→      color = 'rgba(251,113,133,0.7)';  // rose — off beat
689→    }
690→
691→    // Dot
692→    ctx.beginPath();
693→    ctx.arc(x, H / 2, 5, 0, Math.PI * 2);
694→    ctx.fillStyle = color;
695→    ctx.fill();
696→
697→    // Glow
698→    ctx.beginPath();
699→    ctx.arc(x, H / 2, 8, 0, Math.PI * 2);
700→    ctx.fillStyle = color.replace(/[\d.]+\)$/, '0.15)');
701→    ctx.fill();
702→  }
703→
704→  // "Now" line
705→  const nowX = ((now - windowStart) / windowDuration) * W;
706→  ctx.strokeStyle = 'rgba(255,255,255,0.3)';
707→  ctx.lineWidth = 1;
708→  ctx.setLineDash([3, 3]);
709→  ctx.beginPath();
710→  ctx.moveTo(nowX, 0);
711→  ctx.lineTo(nowX, H);
712→  ctx.stroke();
713→  ctx.setLineDash([]);
714→
715→  // Trim old onsets (keep last 30 seconds)
716→  while (onsets.length > 0 && onsets[0].time < now - 30) {
717→    onsets.shift();
718→  }
719→}
720→
721→// --- Onset Detection ---
722→function detectOnset() {
723→  if (!analyser) return;
724→  const timeDomainData = new Uint8Array(analyser.fftSize);
725→  analyser.getByteTimeDomainData(timeDomainData);
726→
727→  let sum = 0;
728→  for (let i = 0; i < timeDomainData.length; i++) {
729→    const v = (timeDomainData[i] - 128) / 128;
730→    sum += v * v;
731→  }
732→  const rms = Math.sqrt(sum / timeDomainData.length);
733→  const now = performance.now() / 1000 - sessionStartTime;
734→
735→  if (rms > ONSET_THRESHOLD && prevRms < ONSET_THRESHOLD * 0.7 && (now - lastOnsetTime) > ONSET_COOLDOWN) {
736→    onsets.push({ time: now });
737→    lastOnsetTime = now;
738→  }
739→  prevRms = rms;
740→}
741→
742→// --- Level Meter ---
743→function updateLevelMeter() {
744→  if (!analyser) return;
745→  const data = new Uint8Array(analyser.fftSize);
746→  analyser.getByteTimeDomainData(data);
747→  let max = 0;
748→  for (let i = 0; i < data.length; i++) {
749→    const v = Math.abs(data[i] - 128);
750→    if (v > max) max = v;
751→  }
752→  const pct = Math.min(100, (max / 128) * 100);
753→  document.getElementById('levelBar').style.width = pct + '%';
754→  document.getElementById('levelLabel').textContent = Math.round(pct);
755→}
756→
757→// ============================================================================
