      if (event.data instanceof ArrayBuffer) {
        queueAudio(event.data);
      } else {
        var msg = JSON.parse(event.data);
        if (msg.type === 'input_transcript') {
          addTranscript('user', msg.text);
        } else if (msg.type === 'output_transcript') {
          addTranscript('agent', msg.text);
          detectScene(msg.text);
          detectAchievement(msg.text);
          detectQuestPhase(msg.text);
          detectCoachingTip(msg.text);
        }
      }
    };

    ws.onclose = function() { setStatus('disconnected'); addTranscript('system', 'Disconnected.'); };
    ws.onerror = function() { setStatus('error'); };

  } catch (err) {
    console.error('Failed to start session:', err);
    setStatus('error');
    addTranscript('system', 'Error: ' + err.message);
    document.getElementById('btnStart').disabled = false;
    document.getElementById('btnStop').disabled = true;
  }
}

function stopSession() {
  sessionActive = false;
  if (ws && ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify({ type: 'close' }));
    ws.close();
  }
  ws = null;
  if (videoInterval) { clearInterval(videoInterval); videoInterval = null; }
  if (animFrame) { cancelAnimationFrame(animFrame); animFrame = null; }

