file.content:
.scene-card[data-scene="shadow_passage"] { border-color: rgba(255,255,255,0.06); }
.scene-card[data-scene="shadow_passage"] .scene-title { color: rgba(255,255,255,0.4); }
.scene-card[data-scene="sunrise_peak"] .scene-bg { background: linear-gradient(135deg, #4a2810, #5a3818, #3a1a08); }
.scene-card[data-scene="sunrise_peak"] { border-color: rgba(251,146,60,0.25); }
.scene-card[data-scene="sunrise_peak"] .scene-title { color: #fb923c; }

/* Viz canvases */
.viz-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.viz-canvas-wrap { padding: 10px; }
canvas { width: 100%; display: block; border-radius: 4px; }
.bpm-control { display: flex; align-items: center; gap: 6px; margin-left: auto; }
.bpm-control label { font-size: 9px; color: var(--text3); }
.bpm-control input[type=range] { width: 60px; accent-color: var(--green); }
.bpm-control .bpm-val { font-size: 10px; color: var(--green); min-width: 20px; }

/* Transcript */
.transcript-panel { flex: 1; min-height: 160px; }
.transcript-body {
  padding: 10px 12px; max-height: 220px; overflow-y: auto;
  font-size: 12px; line-height: 1.5;
}
.transcript-body::-webkit-scrollbar { width: 3px; }
.transcript-body::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 2px; }
.msg { padding: 4px 0; border-bottom: 1px solid rgba(255,255,255,0.02); }
.msg:last-child { border-bottom: none; }
.msg .role { font-size: 9px; font-weight: 600; letter-spacing: 0.04em; margin-bottom: 1px; }
.msg.user .role { color: var(--blue); }
.msg.agent .role { color: var(--amber); }
.msg .content { color: var(--text2); }
.msg.system { color: var(--text3); font-size: 10px; font-style: italic; }

/* Achievement popup */
.achievement-popup {
  position: fixed; top: 20px; right: 20px; z-index: 100;
  padding: 12px 20px; border-radius: 12px;
  background: rgba(251,191,36,0.15); border: 1px solid rgba(251,191,36,0.3);
  backdrop-filter: blur(12px);
  animation: achieveSlide 0.5s ease-out, achieveFade 0.5s 2.5s ease-in forwards;
  display: flex; align-items: center; gap: 10px;
}

